# CA policy: block high sign-in risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Block High Sign-in Risk'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('high')
    }
    GrantControls = @{
        Operator = 'OR'
        BuiltInControls = @('block')
    }
}

# CA policy: require MFA for medium sign-in risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: MFA for Medium Sign-in Risk'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('medium')
    }
    GrantControls = @{
        Operator = 'OR'
        BuiltInControls = @('mfa')
    }
}

# CA policy: require password change for high user risk
# (SSPR must be enabled for users; completing SSPR auto-remediates user risk)
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Password Change for High User Risk'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        UserRiskLevels = @('high')
    }
    GrantControls = @{
        Operator = 'AND'
        BuiltInControls = @('mfa', 'passwordChange')
    }
}

# Bulk investigation: get all high-risk users + their recent detections
$riskyUsers = Get-MgRiskyUser -Filter "riskLevel eq 'high' and riskState eq 'atRisk'"
Write-Host "High-risk users: $($riskyUsers.Count)"

foreach ($user in $riskyUsers) {
    Write-Host "`n=== $($user.UserPrincipalName) ==="
    Write-Host "Risk Level: $($user.RiskLevel)  |  Last Updated: $($user.RiskLastUpdatedDateTime)"

    # Get detections for this user in the last 90 days
    $detections = Get-MgRiskDetection -Filter \
        "userId eq '$($user.Id)' and activityDateTime ge $(Get-Date).AddDays(-90).ToString('yyyy-MM-ddTHH:mm:ssZ')"

    foreach ($d in $detections) {
        Write-Host "  [$($d.ActivityDateTime)] $($d.RiskEventType) — $($d.RiskLevel) — IP: $($d.IpAddress)"
    }

    # Get recent sign-in history for context
    $signIns = Get-MgAuditLogSignIn \
        -Filter "userId eq '$($user.Id)' and createdDateTime ge $(Get-Date).AddDays(-7).ToString('yyyy-MM-ddTHH:mm:ssZ')" \
        -Top 5
    foreach ($s in $signIns) {
        Write-Host "  SignIn: $($s.CreatedDateTime) — $($s.AppDisplayName) — $($s.IpAddress) — Result: $($s.Status.ErrorCode)"
    }
}

# Use diagnostic settings to stream IdentityProtection logs to Log Analytics
# In Azure portal: Entra ID → Monitoring → Diagnostic settings → + Add setting
# Select: RiskyUsers, UserRiskEvents, RiskyServicePrincipals, ServicePrincipalRiskEvents

# Once streaming, query the risk tables in Log Analytics:

# List all tables available in AAD diagnostic logs
# AADRiskyUsers, AADUserRiskEvents, AADRiskyServicePrincipals, AADServicePrincipalRiskEvents

# PowerShell: configure diagnostic settings via Azure REST API
$diagBody = @{
    Properties = @{
        WorkspaceId = '/subscriptions/<sub>/resourceGroups/<rg>/providers/Microsoft.OperationalInsights/workspaces/<ws>'
        Logs = @(
            @{ Category = 'RiskyUsers'; Enabled = $true; RetentionPolicy = @{ Days = 90; Enabled = $true } },
            @{ Category = 'UserRiskEvents'; Enabled = $true; RetentionPolicy = @{ Days = 90; Enabled = $true } },
            @{ Category = 'RiskyServicePrincipals'; Enabled = $true; RetentionPolicy = @{ Days = 90; Enabled = $true } }
        )
    }
} | ConvertTo-Json -Depth 6

Invoke-AzRestMethod -Method PUT \
    -Path '/providers/Microsoft.Aadiam/diagnosticSettings/IdentityProtection?api-version=2017-04-01-preview' \
    -Payload $diagBody
